#include <iostream>
using namespace std;

class A {
public:
 A() { cout << "Constructor A called" << endl; }
 void show() { cout << "Show from A" << endl; }
};

class B : virtual public A {
public:
 B() { cout << "Constructor B called" << endl; }
};

class C : virtual public A {
public:
 C() { cout << "Constructor C called" << endl; }
};

class D : public B, public C {
public:
 D() { cout << "Constructor D called" << endl; }
};

int main() {
 cout << "Creating object of class D:" << endl;
 D obj;
 cout << "\nSize of A: " << sizeof(A) << endl;
 cout << "Size of D: " << sizeof(D) << endl;
 cout << "\nCalling show(): ";
 obj.show(); // No ambiguity now!
 return 0;
}

#include <iostream>
using namespace std;

class Person {
public:
 string name;
 Person(string n) : name(n) {}
 void display() { cout << "Name: " << name << endl; }
};

class Student : virtual public Person {
public:
 int marks;
 Student(string n, int m) : Person(n), marks(m) {}
 void show() { cout << "Student: " << name << ", Marks: " << marks << endl; }
};

class Teacher : virtual public Person {
public:
 int salary;
 Teacher(string n, int s) : Person(n), salary(s) {}
 void show() { cout << "Teacher: " << name << ", Salary: " << salary << endl; }
};

class TeachingAssistant : public Student, public Teacher {
public:
 TeachingAssistant(string n, int m, int s) : Person(n), Student(n, m), Teacher(n, s) {}
 void showAll() {
 cout << "As Student: ";
 Student::show();
 cout << "As Teacher: ";
 Teacher::show();
 }
};

int main() {
 TeachingAssistant ta("John", 90, 50000);
 ta.display(); // Access Person's method
 ta.showAll(); // Access through intermediate classes
 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 int x;
 Base(int val) : x(val) { 
 cout << "Base constructor: x = " << x << endl; 
 }
};

class Derived1 : virtual public Base {
public:
 Derived1(int val) : Base(val * 2) { 
 cout << "Derived1 constructor" << endl; 
 }
};

class Derived2 : virtual public Base {
public:
 Derived2(int val) : Base(val * 3) { 
 cout << "Derived2 constructor" << endl; 
 }
};

class MostDerived : public Derived1, public Derived2 {
public:
 // MostDerived MUST call Base constructor - only this can initialize virtual Base
 MostDerived(int val) : Base(val), Derived1(val), Derived2(val) { 
 cout << "MostDerived constructor" << endl; 
 }
};

int main() {
 MostDerived obj(10);
 cout << "x = " << obj.x << endl; // Only one x exists
 return 0;
}

#include <iostream>
using namespace std;

// Without virtual inheritance (diamond problem)
class A1 { int a; };
class B1 : public A1 { int b; };
class C1 : public A1 { int c; };
class D1 : public B1, public C1 { int d; };

// With virtual inheritance (solution)
class A2 { int a; };
class B2 : virtual public A2 { int b; };
class C2 : virtual public A2 { int c; };
class D2 : public B2, public C2 { int d; };

int main() {
 cout << "=== Size Comparison ===" << endl;
 cout << "Without Virtual:" << endl;
 cout << " Size of A1: " << sizeof(A1) << endl;
 cout << " Size of B1: " << sizeof(B1) << endl;
 cout << " Size of C1: " << sizeof(C1) << endl;
 cout << " Size of D1: " << sizeof(D1) << endl;

 cout << "\nWith Virtual:" << endl;
 cout << " Size of A2: " << sizeof(A2) << endl;
 cout << " Size of B2: " << sizeof(B2) << endl;
 cout << " Size of C2: " << sizeof(C2) << endl;
 cout << " Size of D2: " << sizeof(D2) << endl;

 // D1 has 2 copies of A1 (2*4 = 8), D2 has 1 copy + vbptr
 return 0;
}
